import { Injectable, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Observable } from 'rxjs';
import { API_BASE } from '../api';
import { Order, OrderStatus } from '../models';

export interface CheckoutInput {
  shipName: string;
  shipAddress: string;
}

@Injectable({ providedIn: 'root' })
export class OrderService {
  private readonly http = inject(HttpClient);

  checkout(input: CheckoutInput): Observable<Order> {
    return this.http.post<Order>(`${API_BASE}/orders`, input);
  }

  listMine(): Observable<Order[]> {
    return this.http.get<Order[]>(`${API_BASE}/orders`);
  }

  get(id: string): Observable<Order> {
    return this.http.get<Order>(`${API_BASE}/orders/${id}`);
  }

  listAll(): Observable<Order[]> {
    return this.http.get<Order[]>(`${API_BASE}/orders/admin/all`);
  }

  advanceStatus(id: string, status: OrderStatus): Observable<Order> {
    return this.http.patch<Order>(`${API_BASE}/orders/${id}/status`, { status });
  }
}
